package fop.examples.embedding.embedding.tools;

public abstract class AbstractObjectReader implements XMLReader { private static final String NAMESPACES = "http://xml.org/sax/features/namespaces" ; private static final String NS_PREFIXES = "http://xml.org/sax/features/namespace-prefixes" ; private Map features = new java . util . HashMap ( ) ; private ContentHandler orgHandler ; protected EasyGenerationContentHandlerProxy handler ; protected ErrorHandler errorHandler ; public AbstractObjectReader ( ) { setFeature ( NAMESPACES , false ) ; setFeature ( NS_PREFIXES , false ) ; } public ContentHandler getContentHandler ( ) { return this . orgHandler ; } public void setContentHandler ( ContentHandler handler ) { this . orgHandler = handler ; this . handler = new EasyGenerationContentHandlerProxy ( handler ) ; } public ErrorHandler getErrorHandler ( ) { return this . errorHandler ; } public void setErrorHandler ( ErrorHandler handler ) { this . errorHandler = handler ; } public DTDHandler getDTDHandler ( ) { return null ; } public void setDTDHandler ( DTDHandler handler ) { } public EntityResolver getEntityResolver ( ) { return null ; } public void setEntityResolver ( EntityResolver resolver ) { } public Object getProperty ( String name ) { return null ; } public void setProperty ( String name , Object value ) { } public boolean getFeature ( String name ) { return ( Boolean ) features . get ( name ) ; } protected boolean isNamespaces ( ) { return getFeature ( NAMESPACES ) ; } protected boolean isNamespacePrefixes ( ) { return getFeature ( NS_PREFIXES ) ; } public void setFeature ( String name , boolean value ) { this . features . put ( name , value ) ; } public void parse ( String systemId ) throws IOException , SAXException { throw new SAXException ( this . getClass ( ) . getName ( ) + " cannot be used with system identifiers (URIs)" ) ; } public abstract void parse ( InputSource input ) throws IOException , SAXException ; }